test_that("simple_table: Simple table with header", {
  html <- "<table><thead><tr><th>Name</th><th>Age</th></tr></thead><tbody><tr><td>Alice</td><td>30</td></tr></tbody></table>"
  result <- convert(html)
  content <- result$content %||% ""

  # content_contains_all
  expect_true(grepl("Name", content, fixed = TRUE))
  expect_true(grepl("Age", content, fixed = TRUE))
  expect_true(grepl("Alice", content, fixed = TRUE))
  expect_true(grepl("30", content, fixed = TRUE))
  expect_true(grepl("|", content, fixed = TRUE))
  expect_true(grepl("---", content, fixed = TRUE))
})

